5. var builder = WebApplication.CreateBuilder(args);
6. 
7. var mlContext = new MLContext(seed: 42);
8. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
9. 
10. // Load CSV and map "Yes"/"No" → boolean Label
11. var rawData = mlContext.Data.LoadFromTextFile<ChurnInput>(
12.     dataPath, hasHeader: true, separatorChar: ',');
13. 
14. var mappedData = mlContext.Transforms
15.     .CustomMapping<ChurnInput, ChurnLabel>(
16.         (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
17.         contractName: null)
18.     .Fit(rawData).Transform(rawData);
19. 
20. // Train/test split — never evaluate on training data
21. var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2);
22. 
23. // Feature pipeline: one-hot encode Region, concatenate numeric + encoded features
24. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
25.     .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
26.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
27.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());
28. 
29. var model = pipeline.Fit(split.TrainSet);
30. 
31. // Evaluate and log metrics (test set may be tiny — guard against edge cases)
32. var predictions = model.Transform(split.TestSet);
33. try
34. {
35.     var metrics = mlContext.BinaryClassification.Evaluate(predictions);
36.     Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}  AUC: {metrics.AreaUnderRocCurve:F4}  F1: {metrics.F1Score:F4}");
37. }
38. catch (ArgumentOutOfRangeException)
39. {
40.     Console.WriteLine("Warning: Test set too small to compute all metrics. Add more data for reliable evaluation.");
41. }
42. 
43. // Save model and register pooled prediction engine (thread-safe)
44. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
45. mlContext.Model.Save(model, mappedData.Schema, modelPath);
46. 
47. builder.Services.AddPredictionEnginePool<ChurnPredictionInput, ChurnPrediction>()
48.     .FromFile(modelPath);
49. 
50. var app = builder.Build();
51. 
52. app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");
53. 
