 using Microsoft.ML;
 using Microsoft.Extensions.ML;
 using ChurnPredictor.Models;

 var builder = WebApplication.CreateBuilder(args);

 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

 // Load CSV and map "Yes"/"No" → boolean Label
 var rawData = mlContext.Data.LoadFromTextFile<ChurnInput>(
     dataPath, hasHeader: true, separatorChar: ',');

 var mappedData = mlContext.Transforms
     .CustomMapping<ChurnInput, ChurnLabel>(
         (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
         contractName: null)
     .Fit(rawData).Transform(rawData);

 // Train/test split — never evaluate on training data
 var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2);

 // Feature pipeline: one-hot encode Region, concatenate numeric + encoded features
 var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
     .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

 var model = pipeline.Fit(split.TrainSet);

 // Evaluate and log metrics (test set may be tiny — guard against edge cases)
 var predictions = model.Transform(split.TestSet);
 try
 {
     var metrics = mlContext.BinaryClassification.Evaluate(predictions);
     Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}  AUC: {metrics.AreaUnderRocCurve:F4}  F1: {metrics.F1Score:F4}");
 }
 catch (ArgumentOutOfRangeException)
 {
     Console.WriteLine("Warning: Test set too small to compute all metrics. Add more data for reliable evaluation.");
 }

 // Save model and register pooled prediction engine (thread-safe)
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
 mlContext.Model.Save(model, mappedData.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<ChurnPredictionInput, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<ChurnPredictionInput, ChurnPrediction> pool, ChurnRequest req) =>
 {
     var input = new ChurnPredictionInput
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };
     var result = pool.Predict(input);
     return Results.Ok(new { WillChurn = result.Churned, result.Probability });
 });

 app.Run();

 record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

